/**
 * ESLint rule: eslint-disable-require-reason
 *
 * Требует обоснование отключения правил ESLint в форматах:
 * 1. Для блочных комментариев eslint-disable с обоснованием на той же строке
 * 2. Для строчных комментариев eslint-disable-next-line с обоснованием на предыдущей строке
 */

export default {
    meta: {
        type: "problem",
        docs: {
            description: "Require reason for eslint-disable comments",
            category: "Best Practices",
            recommended: true
        },
        fixable: null,
        schema: [],
        messages: {
            missingReason: "ESLint disable comment must include reason in format: '/* eslint-disable {{rules}} */  // Правило отключено: {reason}'",
            invalidFormat: "ESLint disable comment reason must follow format: '// Правило отключено: {reason}' on the same line",
            missingReasonNextLine: "ESLint disable-next-line comment must be preceded by reason comment in format: '// Правило отключено: {reason}' on the previous line",
        },
    },

    create(context) {
        const sourceCode = context.getSourceCode();

        return {
            Program() {
                const comments = sourceCode.getAllComments();

                comments.forEach((comment) => {
                    // Проверяем блочные комментарии, содержащие eslint-disable
                    if (comment.type === "Block" && comment.value.includes("eslint-disable")) {
                        const commentValue = comment.value.trim();

                        // Извлекаем правила из комментария
                        const disableMatch = commentValue.match(/eslint-disable\s+([^*]+)/);
                        if (!disableMatch) {
                            return;
                        }

                        const rules = disableMatch[1].trim();
                        const commentLine = comment.loc.end.line;

                        // Получаем весь текст строки с комментарием
                        const lines = sourceCode.getLines();
                        const currentLine = lines[commentLine - 1];

                        // Проверяем, есть ли обоснование на той же строке
                        const reasonPattern = /\/\*\s*eslint-disable[^*]*\*\/\s*\/\/\s*Правило отключено:\s*.+/;

                        if (!reasonPattern.test(currentLine)) {
                            context.report({
                                node: {
                                    type: "Program",
                                    loc: comment.loc,
                                    range: comment.range
                                },
                                messageId: "missingReason",
                                data: {
                                    rules: rules
                                }
                            });
                        } else {
                            // Проверяем правильность формата обоснования
                            const expectedFormat = new RegExp(
                                `\\/\\*\\s*eslint-disable\\s+${rules.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}\\s*\\*\\/\\s*\\/\\/\\s*Правило отключено:\\s*.+`
                            );

                            if (!expectedFormat.test(currentLine)) {
                                context.report({
                                    node: {
                                        type: "Program",
                                        loc: comment.loc,
                                        range: comment.range
                                    },
                                    messageId: "invalidFormat"
                                });
                            }
                        }
                    }

                    // Проверяем строчные комментарии, содержащие eslint-disable-next-line
                    if (comment.type === "Line" && comment.value.includes("eslint-disable-next-line")) {
                        const commentValue = comment.value.trim();
                        const commentLine = comment.loc.start.line;

                        // Получаем все строки с комментариями
                        const lines = sourceCode.getLines();

                        // Проверяем предыдущую строку на наличие обоснования
                        const previousLine = commentLine > 1 ? lines[commentLine - 2] : "";
                        const reasonPattern = /\/\/\s*Правило отключено:\s*.+/;

                        if (!reasonPattern.test(previousLine.trim())) {
                            // Извлекаем правила для сообщения об ошибке
                            const eslintIndex = commentValue.indexOf('eslint-disable-next-line');
                            if (eslintIndex === -1) {
                                return;
                            }
                            
                            const rulesStart = eslintIndex + 'eslint-disable-next-line'.length;
                            const rulesText = commentValue.substring(rulesStart).trim();
                            
                            // Разделяем по пробелам и ищем правила до первого комментария
                            const parts = rulesText.split(/\s+/);
                            const rules = [];
                            
                            for (const part of parts) {
                                if (part.startsWith('//')) {
                                    break; // Нашли начало комментария
                                }
                                if (part.length > 0) {
                                    rules.push(part);
                                }
                            }
                            
                            const rulesString = rules.length > 0 ? rules.join(' ') : "rules";

                            context.report({
                                node: {
                                    type: "Program",
                                    loc: comment.loc,
                                    range: comment.range
                                },
                                messageId: "missingReasonNextLine",
                                data: {
                                    rules: rulesString
                                }
                            });
                        }
                    }
                });
            }
        };
    }
};
